import { useEffect, useMemo, useRef, useState } from "react";
import { Link, useNavigate, useLocation } from "react-router-dom";
import api from "../../api/axios";
import { getUserFromToken } from "../../utils/auth";

function Navbar() {
  const navigate = useNavigate();
  const location = useLocation();
  const userMenuRef = useRef(null);

  const fallbackUser = getUserFromToken();

  const [user, setUser] = useState(fallbackUser);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isUserMenuOpen, setIsUserMenuOpen] = useState(false);
  const [isMobileView, setIsMobileView] = useState(() => window.innerWidth <= 920);

  const fetchCurrentUser = async ({ silent = false } = {}) => {
    const currentToken = localStorage.getItem("token");

    if (!currentToken) {
      setUser(null);
      return;
    }

    try {
      const response = await api.get("/auth/me");
      const currentUser = response?.data?.data || null;

      if (currentUser) {
        setUser(currentUser);
        localStorage.setItem("user", JSON.stringify(currentUser));
      } else if (!silent) {
        setUser(getUserFromToken());
      }
    } catch (err) {
      console.error(err);
      setUser(getUserFromToken());
    }
  };

  useEffect(() => {
    fetchCurrentUser({ silent: true });
  }, [location.pathname]);

  useEffect(() => {
    const handleProfileUpdated = () => {
      fetchCurrentUser({ silent: true });
    };

    const handleStorageChange = () => {
      setUser(getUserFromToken());
    };

    window.addEventListener("profile-updated", handleProfileUpdated);
    window.addEventListener("storage", handleStorageChange);

    return () => {
      window.removeEventListener("profile-updated", handleProfileUpdated);
      window.removeEventListener("storage", handleStorageChange);
    };
  }, []);

  useEffect(() => {
    setIsMobileMenuOpen(false);
    setIsUserMenuOpen(false);
  }, [location.pathname]);

  useEffect(() => {
    const handleResize = () => {
      const mobile = window.innerWidth <= 920;
      setIsMobileView(mobile);

      if (!mobile) {
        setIsMobileMenuOpen(false);
      }
    };

    window.addEventListener("resize", handleResize);

    return () => {
      window.removeEventListener("resize", handleResize);
    };
  }, []);

  useEffect(() => {
    const handleClickOutside = (event) => {
      if (userMenuRef.current && !userMenuRef.current.contains(event.target)) {
        setIsUserMenuOpen(false);
      }
    };

    const handleEscape = (event) => {
      if (event.key === "Escape") {
        setIsUserMenuOpen(false);
        setIsMobileMenuOpen(false);
      }
    };

    document.addEventListener("mousedown", handleClickOutside);
    document.addEventListener("keydown", handleEscape);

    return () => {
      document.removeEventListener("mousedown", handleClickOutside);
      document.removeEventListener("keydown", handleEscape);
    };
  }, []);

  const scrollToTopSmooth = () => {
    window.scrollTo({
      top: 0,
      behavior: "smooth",
    });
  };

  const handleNavClick = (event, path) => {
    if (location.pathname === path) {
      event.preventDefault();
      setIsMobileMenuOpen(false);
      setIsUserMenuOpen(false);
      scrollToTopSmooth();
    }
  };

  const handleNavigateWithTop = (path) => {
    setIsMobileMenuOpen(false);
    setIsUserMenuOpen(false);

    if (location.pathname === path) {
      scrollToTopSmooth();
      return;
    }

    navigate(path);
  };

  const handleLogout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("user");
    setUser(null);
    setIsMobileMenuOpen(false);
    setIsUserMenuOpen(false);
    navigate("/login");
  };

  const isActive = (path) => location.pathname === path;

  const getDisplayName = (fullName) => {
    if (!fullName) return "Usuari";
    return fullName.split(" ")[0];
  };

  const getInitials = (fullName) => {
    if (!fullName) return "U";

    const parts = fullName.trim().split(" ").filter(Boolean);

    if (parts.length === 1) {
      return parts[0].slice(0, 1).toUpperCase();
    }

    return `${parts[0][0]}${parts[1][0]}`.toUpperCase();
  };

  const userName = getDisplayName(user?.nom);
  const userEmail = user?.email || "";
  const userRoleLabel = user?.rol === "admin" ? "Administrador" : "Usuari";

  const navLinks = useMemo(() => {
    const links = [
      { to: "/", label: "Inici" },
      { to: "/availability", label: "Disponibilitat" },
    ];

    if (user) {
      links.push({ to: "/my-reservations", label: "Les meves reserves" });

      if (user?.rol === "admin") {
        links.push({ to: "/admin", label: "Administració" });
      }
    }

    return links;
  }, [user]);

  return (
    <nav className="pb-navbar">
      <div className="pb-navbar__inner">
        <div className="pb-navbar__left">
          <Link
            to="/"
            className="pb-navbar__brand"
            aria-label="Anar a l'inici"
            onClick={(event) => handleNavClick(event, "/")}
          >
            <span className="pb-navbar__brand-mark">PB</span>

            <span className="pb-navbar__brand-copy">
              <span className="pb-navbar__brand-title">PadelBook</span>
              <span className="pb-navbar__brand-subtitle">Reserves de pàdel</span>
            </span>
          </Link>
        </div>

        {!isMobileView && (
          <div className="pb-navbar__center">
            <div className="pb-navbar__links">
              {navLinks.map((link) => (
                <Link
                  key={link.to}
                  to={link.to}
                  className={`pb-navbar__link ${isActive(link.to) ? "is-active" : ""}`}
                  onClick={(event) => handleNavClick(event, link.to)}
                >
                  {link.label}
                </Link>
              ))}
            </div>
          </div>
        )}

        <div className="pb-navbar__right">
          {user ? (
            <div className="pb-navbar__user" ref={userMenuRef}>
              <button
                type="button"
                className={`pb-navbar__user-trigger ${isUserMenuOpen ? "is-open" : ""}`}
                onClick={() => setIsUserMenuOpen((prev) => !prev)}
                aria-label="Obrir menú d'usuari"
                aria-haspopup="menu"
                aria-expanded={isUserMenuOpen}
              >
                <span className="pb-navbar__avatar">{getInitials(user?.nom)}</span>

                {!isMobileView && (
                  <span className="pb-navbar__user-meta">
                    <span className="pb-navbar__user-name">{userName}</span>
                    <span className="pb-navbar__user-role">{userRoleLabel}</span>
                  </span>
                )}

                {!isMobileView && (
                  <span className="pb-navbar__chevron" aria-hidden="true">
                    <svg
                      viewBox="0 0 20 20"
                      fill="none"
                      xmlns="http://www.w3.org/2000/svg"
                    >
                      <path
                        d="M5 7.5L10 12.5L15 7.5"
                        stroke="currentColor"
                        strokeWidth="1.8"
                        strokeLinecap="round"
                        strokeLinejoin="round"
                      />
                    </svg>
                  </span>
                )}
              </button>

              {isUserMenuOpen && (
                <div className="pb-navbar__dropdown" role="menu">
                  <div className="pb-navbar__dropdown-head">
                    <span className="pb-navbar__dropdown-name">{user?.nom || "Usuari"}</span>
                    <span className="pb-navbar__dropdown-role">{userRoleLabel}</span>
                    {userEmail && (
                      <span className="pb-navbar__dropdown-email">{userEmail}</span>
                    )}
                  </div>

                  <div className="pb-navbar__dropdown-body">
                    <button
                      type="button"
                      className="pb-navbar__dropdown-item"
                      onClick={() => handleNavigateWithTop("/my-account")}
                    >
                      <span className="pb-navbar__dropdown-icon" aria-hidden="true">
                        <svg
                          viewBox="0 0 20 20"
                          fill="none"
                          xmlns="http://www.w3.org/2000/svg"
                        >
                          <path
                            d="M10 10C12.2091 10 14 8.20914 14 6C14 3.79086 12.2091 2 10 2C7.79086 2 6 3.79086 6 6C6 8.20914 7.79086 10 10 10Z"
                            stroke="currentColor"
                            strokeWidth="1.6"
                          />
                          <path
                            d="M3 17C3.87518 14.3766 6.49511 12.5 10 12.5C13.5049 12.5 16.1248 14.3766 17 17"
                            stroke="currentColor"
                            strokeWidth="1.6"
                            strokeLinecap="round"
                          />
                        </svg>
                      </span>
                      <span>El meu compte</span>
                    </button>

                    {user?.rol === "admin" && (
                      <button
                        type="button"
                        className="pb-navbar__dropdown-item"
                        onClick={() => handleNavigateWithTop("/admin")}
                      >
                        <span className="pb-navbar__dropdown-icon" aria-hidden="true">
                          <svg
                            viewBox="0 0 20 20"
                            fill="none"
                            xmlns="http://www.w3.org/2000/svg"
                          >
                            <path
                              d="M10 2L12.25 4.25L15.5 4.5L15.75 7.75L18 10L15.75 12.25L15.5 15.5L12.25 15.75L10 18L7.75 15.75L4.5 15.5L4.25 12.25L2 10L4.25 7.75L4.5 4.5L7.75 4.25L10 2Z"
                              stroke="currentColor"
                              strokeWidth="1.4"
                              strokeLinejoin="round"
                            />
                            <path
                              d="M10 12.5C11.3807 12.5 12.5 11.3807 12.5 10C12.5 8.61929 11.3807 7.5 10 7.5C8.61929 7.5 7.5 8.61929 7.5 10C7.5 11.3807 8.61929 12.5 10 12.5Z"
                              stroke="currentColor"
                              strokeWidth="1.4"
                            />
                          </svg>
                        </span>
                        <span>Administració</span>
                      </button>
                    )}

                    <button
                      type="button"
                      className="pb-navbar__dropdown-item is-danger"
                      onClick={handleLogout}
                    >
                      <span className="pb-navbar__dropdown-icon" aria-hidden="true">
                        <svg
                          viewBox="0 0 20 20"
                          fill="none"
                          xmlns="http://www.w3.org/2000/svg"
                        >
                          <path
                            d="M8 4H5.75C5.05964 4 4.5 4.55964 4.5 5.25V14.75C4.5 15.4404 5.05964 16 5.75 16H8"
                            stroke="currentColor"
                            strokeWidth="1.6"
                            strokeLinecap="round"
                          />
                          <path
                            d="M11.5 13.5L15 10L11.5 6.5"
                            stroke="currentColor"
                            strokeWidth="1.6"
                            strokeLinecap="round"
                            strokeLinejoin="round"
                          />
                          <path
                            d="M15 10H8"
                            stroke="currentColor"
                            strokeWidth="1.6"
                            strokeLinecap="round"
                          />
                        </svg>
                      </span>
                      <span>Tancar sessió</span>
                    </button>
                  </div>
                </div>
              )}
            </div>
          ) : (
            !isMobileView && (
              <div className="pb-navbar__guest-actions">
                <Link
                  to="/login"
                  className="btn btn-light btn-sm"
                  onClick={(event) => handleNavClick(event, "/login")}
                >
                  Iniciar sessió
                </Link>
                <Link
                  to="/register"
                  className="btn btn-primary btn-sm"
                  onClick={(event) => handleNavClick(event, "/register")}
                >
                  Crear compte
                </Link>
              </div>
            )
          )}

          {isMobileView && (
            <button
              type="button"
              className={`pb-navbar__mobile-toggle ${isMobileMenuOpen ? "is-open" : ""}`}
              onClick={() => setIsMobileMenuOpen((prev) => !prev)}
              aria-label={isMobileMenuOpen ? "Tancar menú" : "Obrir menú"}
              aria-expanded={isMobileMenuOpen}
            >
              <span className="pb-navbar__mobile-toggle-line" />
              <span className="pb-navbar__mobile-toggle-line" />
              <span className="pb-navbar__mobile-toggle-line" />
            </button>
          )}
        </div>
      </div>

      {isMobileView && isMobileMenuOpen && (
        <div className="pb-navbar__mobile-panel">
          <div className="pb-navbar__mobile-links">
            {navLinks.map((link) => (
              <Link
                key={link.to}
                to={link.to}
                className={`pb-navbar__mobile-link ${isActive(link.to) ? "is-active" : ""}`}
                onClick={(event) => handleNavClick(event, link.to)}
              >
                {link.label}
              </Link>
            ))}
          </div>

          {!user && (
            <div className="pb-navbar__mobile-actions">
              <Link
                to="/login"
                className="btn btn-light btn-full"
                onClick={(event) => handleNavClick(event, "/login")}
              >
                Iniciar sessió
              </Link>
              <Link
                to="/register"
                className="btn btn-primary btn-full"
                onClick={(event) => handleNavClick(event, "/register")}
              >
                Crear compte
              </Link>
            </div>
          )}
        </div>
      )}
    </nav>
  );
}

export default Navbar;

import { useEffect, useMemo, useRef, useState } from "react";
import api from "../../api/axios";
import CreateCourtForm from "../../components/CreateCourtForm/CreateCourtForm";
import CourtCard from "../../components/CourtCard/CourtCard";
import AdminReservationsTable from "../../components/AdminReservationsTable/AdminReservationsTable";
import LoadingSpinner from "../../components/LoadingSpinner/LoadingSpinner";
import { scrollToElementWithOffset, normalizeCollectionResponse } from "../../utils/helpers";
import "./AdminPage.css";

function AdminPage() {
  const emptyCourt = {
    nom_pista: "",
    tipus: "dobles",
    coberta: 0,
    estat: "disponible",
    descripcio: "",
    preu_reserva: "",
  };

  const editSectionRef = useRef(null);
  const dashboardSectionRef = useRef(null);
  const reservationsSectionRef = useRef(null);
  const courtsSectionRef = useRef(null);
  const feedbackRef = useRef(null);

  const [isMobileView, setIsMobileView] = useState(window.innerWidth <= 768);

  const [reservations, setReservations] = useState([]);
  const [courts, setCourts] = useState([]);

  const [overviewStats, setOverviewStats] = useState({});
  const [statsByCourt, setStatsByCourt] = useState([]);
  const [statsByTimeslot, setStatsByTimeslot] = useState([]);
  const [statsByDate, setStatsByDate] = useState([]);
  const [adminLogs, setAdminLogs] = useState([]);

  const [loading, setLoading] = useState(true);
  const [loadingDashboard, setLoadingDashboard] = useState(false);
  const [error, setError] = useState("");

  const [feedback, setFeedback] = useState("");
  const [feedbackType, setFeedbackType] = useState("success");
  const [feedbackAction, setFeedbackAction] = useState(null);

  const [confirmingCourtId, setConfirmingCourtId] = useState(null);
  const [deletingCourtId, setDeletingCourtId] = useState(null);
  const [creatingCourt, setCreatingCourt] = useState(false);
  const [editingCourtId, setEditingCourtId] = useState(null);
  const [highlightedCourtId, setHighlightedCourtId] = useState(null);
  const [activeTab, setActiveTab] = useState("dashboard");

  const [newCourt, setNewCourt] = useState(emptyCourt);

  const [courtSearch, setCourtSearch] = useState("");
  const [courtStatusFilter, setCourtStatusFilter] = useState("totes");
  const [courtTypeFilter, setCourtTypeFilter] = useState("tots");

  useEffect(() => {
    const handleResize = () => {
      setIsMobileView(window.innerWidth <= 768);
    };

    window.addEventListener("resize", handleResize);
    return () => window.removeEventListener("resize", handleResize);
  }, []);

  const scrollToCourtCard = (courtId) => {
    const card = document.getElementById(`court-${courtId}`);
    if (!card) return;

    scrollToElementWithOffset(card, 120);
    setHighlightedCourtId(courtId);

    setTimeout(() => {
      setHighlightedCourtId(null);
    }, 2500);
  };

  const normalizeOverview = (data, reservationsSource = [], courtsSource = []) => {
    return {
      totalReservations:
        data?.totalReservations ??
        data?.total_reservations ??
        data?.reservesTotals ??
        data?.reservations ??
        reservationsSource.length ??
        0,

      activeReservations:
        data?.activeReservations ??
        data?.active_reservations ??
        data?.reservesActives ??
        reservationsSource.filter((reservation) => {
          const status = (reservation.estat || "").toLowerCase();
          return status === "activa" || status === "active";
        }).length,

      cancelledReservations:
        data?.cancelledReservations ??
        data?.cancelled_reservations ??
        data?.canceledReservations ??
        data?.canceled_reservations ??
        data?.reservesCancelades ??
        reservationsSource.filter((reservation) => {
          const status = (reservation.estat || "").toLowerCase();
          return status !== "activa" && status !== "active";
        }).length,

      totalCourts:
        data?.totalCourts ??
        data?.total_courts ??
        data?.pistesTotals ??
        courtsSource.length ??
        0,

      availableCourts:
        data?.availableCourts ??
        data?.available_courts ??
        data?.pistesDisponibles ??
        courtsSource.filter((court) => court.estat === "disponible").length,

      coveredCourts:
        data?.coveredCourts ??
        data?.covered_courts ??
        data?.pistesCobertes ??
        courtsSource.filter((court) => Number(court.coberta) === 1).length,
    };
  };

  const normalizeCourtStat = (item, index) => ({
    id: item?.id ?? item?.court_id ?? item?.pista_id ?? `court-${index}`,
    label:
      item?.nom_pista ??
      item?.court_name ??
      item?.court ??
      item?.name ??
      item?.pista ??
      `Pista ${index + 1}`,
    value:
      Number(
        item?.total ??
          item?.count ??
          item?.reservations ??
          item?.total_reserves ??
          item?.value ??
          0
      ) || 0,
  });

  const normalizeTimeslotStat = (item, index) => ({
    id:
      item?.id ??
      item?.time_slot_id ??
      item?.slot_id ??
      item?.franja_id ??
      `slot-${index}`,
    label:
      item?.hora ??
      item?.time_slot ??
      item?.slot ??
      item?.franja ??
      item?.label ??
      `Franja ${index + 1}`,
    value:
      Number(
        item?.total ??
          item?.count ??
          item?.reservations ??
          item?.total_reserves ??
          item?.value ??
          0
      ) || 0,
  });

  const normalizeDateStat = (item, index) => ({
    id: item?.id ?? item?.date ?? item?.data ?? `date-${index}`,
    label: item?.data ?? item?.date ?? item?.label ?? `Data ${index + 1}`,
    value:
      Number(
        item?.total ??
          item?.count ??
          item?.reservations ??
          item?.total_reserves ??
          item?.value ??
          0
      ) || 0,
  });

  const normalizeLogItem = (log, index) => ({
    id: log?.id ?? `log-${index}`,
    action:
      log?.accio ??
      log?.action ??
      log?.tipus ??
      log?.type ??
      "ACCIO_DESCONEGUDA",
    adminName:
      log?.admin_nom ??
      log?.adminName ??
      log?.admin ??
      log?.nom_admin ??
      log?.user_name ??
      "Administrador",
    adminId: log?.admin_id ?? log?.adminId ?? log?.user_id ?? null,
    details:
      log?.detalls ??
      log?.details ??
      log?.descripcio ??
      log?.description ??
      "",
    createdAt:
      log?.created_at ??
      log?.createdAt ??
      log?.data ??
      log?.date ??
      null,
  });

  const showFeedbackMessage = (message, type = "success", action = null) => {
    setFeedback(message);
    setFeedbackType(type);
    setFeedbackAction(action);

    setTimeout(() => {
      setFeedback("");
      setFeedbackAction(null);
    }, 5000);

    setTimeout(() => {
      scrollToElementWithOffset(feedbackRef.current, 120);
    }, 60);
  };

  const fetchDashboardData = async (
    reservationsSource = reservations,
    courtsSource = courts
  ) => {
    try {
      setLoadingDashboard(true);

      const [overviewRes, byCourtRes, byTimeslotRes, byDateRes, logsRes] =
        await Promise.all([
          api.get("/admin/stats/overview"),
          api.get("/admin/stats/by-court"),
          api.get("/admin/stats/by-timeslot"),
          api.get("/admin/stats/by-date"),
          api.get("/admin/logs?page=1&limit=8"),
        ]);

      setOverviewStats(
        normalizeOverview(overviewRes.data?.data || {}, reservationsSource, courtsSource)
      );
      setStatsByCourt(
        normalizeCollectionResponse(byCourtRes.data).map(normalizeCourtStat)
      );
      setStatsByTimeslot(
        normalizeCollectionResponse(byTimeslotRes.data).map(normalizeTimeslotStat)
      );
      setStatsByDate(
        normalizeCollectionResponse(byDateRes.data).map(normalizeDateStat)
      );
      setAdminLogs(normalizeCollectionResponse(logsRes.data).map(normalizeLogItem));
    } catch (err) {
      console.error(err);
      showFeedbackMessage(
        "No s'han pogut carregar algunes dades del dashboard administratiu.",
        "error"
      );
    } finally {
      setLoadingDashboard(false);
    }
  };

  const fetchAdminData = async () => {
    try {
      setLoading(true);
      setError("");

      const [reservationsRes, courtsRes] = await Promise.all([
        api.get("/admin/reservations"),
        api.get("/courts"),
      ]);

      const normalizedReservations = normalizeCollectionResponse(
        reservationsRes.data
      );
      const normalizedCourts = normalizeCollectionResponse(courtsRes.data);

      setReservations(normalizedReservations);
      setCourts(normalizedCourts);

      return {
        reservations: normalizedReservations,
        courts: normalizedCourts,
      };
    } catch (err) {
      console.error(err);
      setError("Error carregant dades d'administració");
      return { reservations: [], courts: [] };
    } finally {
      setLoading(false);
    }
  };

  const refreshAllAdminData = async () => {
    const baseData = await fetchAdminData();

    const safeReservations = Array.isArray(baseData?.reservations)
      ? baseData.reservations
      : [];

    const safeCourts = Array.isArray(baseData?.courts) ? baseData.courts : [];

    setOverviewStats(normalizeOverview({}, safeReservations, safeCourts));

    await fetchDashboardData(safeReservations, safeCourts);
  };

  const resetCourtForm = () => {
    setNewCourt(emptyCourt);
    setEditingCourtId(null);
  };

  const resetCourtFilters = () => {
    setCourtSearch("");
    setCourtStatusFilter("totes");
    setCourtTypeFilter("tots");
  };

  const handleCreateOrUpdateCourt = async (e) => {
    e.preventDefault();

    try {
      setCreatingCourt(true);

      const payload = {
        ...newCourt,
        coberta: Number(newCourt.coberta),
      };

      if (editingCourtId) {
        await api.put(`/admin/courts/${editingCourtId}`, payload);
        await refreshAllAdminData();

        showFeedbackMessage(
          "La pista s'ha actualitzat correctament.",
          "success",
          {
            label: "Veure pista editada",
            onClick: () => scrollToCourtCard(editingCourtId),
          }
        );

        resetCourtForm();
      } else {
        const createResponse = await api.post("/admin/courts", payload);
        const createdCourtId = createResponse?.data?.data?.id || null;

        const refreshedData = await fetchAdminData();
        await fetchDashboardData(refreshedData.reservations, refreshedData.courts);

        if (createdCourtId) {
          showFeedbackMessage(
            "La pista s'ha creat correctament.",
            "success",
            {
              label: "Veure pista creada",
              onClick: () => scrollToCourtCard(createdCourtId),
            }
          );
        } else {
          const createdMatches = refreshedData.courts.filter(
            (court) => court.nom_pista === payload.nom_pista
          );

          const createdCourt =
            createdMatches.length > 0
              ? createdMatches[createdMatches.length - 1]
              : null;

          if (createdCourt) {
            showFeedbackMessage(
              "La pista s'ha creat correctament.",
              "success",
              {
                label: "Veure pista creada",
                onClick: () => scrollToCourtCard(createdCourt.id),
              }
            );
          } else {
            showFeedbackMessage("La pista s'ha creat correctament.", "success");
          }
        }

        resetCourtForm();
      }
    } catch (err) {
      console.error(err);

      const backendError =
        err.response?.data?.error ||
        (editingCourtId
          ? "No s'han pogut guardar els canvis de la pista."
          : "No s'ha pogut crear la pista. Revisa les dades i torna-ho a provar.");

      showFeedbackMessage(backendError, "error");
    } finally {
      setCreatingCourt(false);
    }
  };

  const handleStartEditCourt = (court) => {
