              >
                <div>
                  <span className="pb-kicker">Gestió d’espais</span>
                  <h2
                    className={`pb-panel-title ${isMobileView ? "admin__section-title--mobile" : ""}`}
                  >
                    Pistes
                  </h2>
                  <p className="pb-panel-text">
                    Cerca, filtra i gestiona les pistes existents amb més rapidesa.
                  </p>
                </div>

                <span className="pb-badge-pill pb-badge-pill--green">
                  {filteredCourts.length} visibles
                </span>
              </div>

              <div className="pb-surface-card admin__section-card">
                <div
                  className={`admin__court-tools-grid ${isMobileView ? "admin__court-tools-grid--mobile" : ""}`}
                >
                  <div className="admin__court-filter-field">
                    <label htmlFor="courtSearch" className="admin__filter-label">
                      Cercar pista
                    </label>
                    <input
                      id="courtSearch"
                      type="text"
                      value={courtSearch}
                      onChange={(e) => setCourtSearch(e.target.value)}
                      placeholder="Nom o descripció..."
                      className="pb-input"
                    />
                  </div>

                  <div className="admin__court-filter-field">
                    <label htmlFor="courtStatusFilter" className="admin__filter-label">
                      Estat
                    </label>
                    <select
                      id="courtStatusFilter"
                      value={courtStatusFilter}
                      onChange={(e) => setCourtStatusFilter(e.target.value)}
                      className="pb-input"
                    >
                      <option value="totes">Totes</option>
                      <option value="disponible">Disponibles</option>
                      <option value="manteniment">Manteniment</option>
                    </select>
                  </div>

                  <div className="admin__court-filter-field">
                    <label htmlFor="courtTypeFilter" className="admin__filter-label">
                      Tipus
                    </label>
                    <select
                      id="courtTypeFilter"
                      value={courtTypeFilter}
                      onChange={(e) => setCourtTypeFilter(e.target.value)}
                      className="pb-input"
                    >
                      <option value="tots">Tots</option>
                      <option value="dobles">Dobles</option>
                      <option value="individual">Individual</option>
                    </select>
                  </div>

                  <div className="admin__court-filter-actions">
                    <button
                      type="button"
                      className="btn btn-light"
                      onClick={resetCourtFilters}
                    >
                      Netejar filtres
                    </button>
                  </div>
                </div>

                <div
                  className={`admin__court-quick-stats ${isMobileView ? "admin__court-quick-stats--mobile" : ""}`}
                >
                  <div className="admin__court-quick-stat">
                    <span className="admin__court-quick-stat-label">Mostrades</span>
                    <span className="admin__court-quick-stat-value">{filteredCourts.length}</span>
                  </div>

                  <div className="admin__court-quick-stat">
                    <span className="admin__court-quick-stat-label">Disponibles</span>
                    <span className="admin__court-quick-stat-value">{filteredAvailableCourtsCount}</span>
                  </div>

                  <div className="admin__court-quick-stat">
                    <span className="admin__court-quick-stat-label">Manteniment</span>
                    <span className="admin__court-quick-stat-value">{filteredMaintenanceCourtsCount}</span>
                  </div>
                </div>
              </div>

              {filteredCourts.length > 0 ? (
                <div
                  className={`admin__cards ${isMobileView ? "admin__cards--mobile" : ""}`}
                >
                  {filteredCourts.map((court) => (
                    <CourtCard
                      key={court.id}
                      court={court}
                      onEdit={() => handleStartEditCourt(court)}
                      onStartDelete={() => {
                        setConfirmingCourtId(court.id);

                        setTimeout(() => {
                          scrollToCourtCard(court.id);
                        }, 150);
                      }}
                      onAbortDelete={() => setConfirmingCourtId(null)}
                      onDelete={() => handleDeleteCourt(court.id)}
                      confirmingDelete={confirmingCourtId === court.id}
                      isDeleting={deletingCourtId === court.id}
                      isHighlighted={highlightedCourtId === court.id}
                    />
                  ))}
                </div>
              ) : (
                <div className="pb-surface-card admin__empty-filtered-state">
                  <p className="admin__empty-filtered-title">No hi ha pistes que coincideixin</p>
                  <p className="admin__empty-filtered-text">
                    Revisa els filtres aplicats o neteja la cerca per tornar a veure
                    totes les pistes.
                  </p>

                  <button
                    type="button"
                    className="btn btn-light"
                    onClick={resetCourtFilters}
                  >
                    Mostrar totes les pistes
                  </button>
                </div>
              )}
            </section>
              </>
            )}
          </>
        )}
      </div>
    </div>
  );
}

export default AdminPage;

import { useEffect, useMemo, useRef, useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import api from "../../api/axios";
import AvailabilityTable from "../../components/AvailabilityTable/AvailabilityTable";
import AvailabilitySummary from "../../components/AvailabilitySummary/AvailabilitySummary";
import LoadingSpinner from "../../components/LoadingSpinner/LoadingSpinner";
import { scrollToElementWithOffset } from "../../utils/helpers";
import "./AvailabilityPage.css";

function AvailabilityPage() {
  const navigate = useNavigate();
  const hiddenDateInputRef = useRef(null);
  const resultsRef = useRef(null);
  const topFeedbackRef = useRef(null);
  const shouldScrollToResultsRef = useRef(false);

  const [reservingSlot, setReservingSlot] = useState(null);
  const [isMobileView, setIsMobileView] = useState(window.innerWidth <= 768);

  const getToday = () => new Date().toISOString().split("T")[0];

  const [date, setDate] = useState(getToday());
  const [availability, setAvailability] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [showOnlyAvailable, setShowOnlyAvailable] = useState(false);
  const [showAuthHelp, setShowAuthHelp] = useState(false);
  const [recentlyReservedSlot, setRecentlyReservedSlot] = useState(null);
  const [paymentMethod, setPaymentMethod] = useState("online_simulat");
  const [reservationSummary, setReservationSummary] = useState(null);

  useEffect(() => {
    const handleResize = () => {
      setIsMobileView(window.innerWidth <= 768);
    };

    window.addEventListener("resize", handleResize);
    return () => window.removeEventListener("resize", handleResize);
  }, []);

  const formatDisplayDate = (dateString) => {
    if (!dateString) return "Cap data seleccionada";

    const dateObj = new Date(dateString);
    return dateObj.toLocaleDateString("ca-ES", {
      weekday: "long",
      day: "numeric",
      month: "long",
      year: "numeric",
    });
  };

  const formatShortWeekday = (dateObj) => {
    return dateObj.toLocaleDateString("ca-ES", { weekday: "short" });
  };

  const isPastDate = (selectedDate) => {
    return selectedDate < getToday();
  };

  const clearMessages = () => {
    setError("");
    setSuccess("");
    setShowAuthHelp(false);
    setReservationSummary(null);
  };

  const handleOpenDatePicker = () => {
    if (hiddenDateInputRef.current) {
      if (hiddenDateInputRef.current.showPicker) {
        hiddenDateInputRef.current.showPicker();
      } else {
        hiddenDateInputRef.current.click();
      }
    }
  };

  const fetchAvailability = async (selectedDate) => {
    try {
      if (!selectedDate) {
        setError("Has de seleccionar una data.");
        setAvailability([]);
        return;
      }

      if (isPastDate(selectedDate)) {
        setError("No pots consultar disponibilitat de dies anteriors a avui.");
        setAvailability([]);
        return;
      }

      setLoading(true);
      setError("");
      setShowAuthHelp(false);

      const response = await api.get(`/availability?date=${selectedDate}`);
      const availabilityData = response?.data?.data || [];

      setAvailability(Array.isArray(availabilityData) ? availabilityData : []);
    } catch (err) {
      console.error(err);
      setError("Error obtenint la disponibilitat.");
      setAvailability([]);
    } finally {
      setLoading(false);
    }
  };

  const changeDay = (amount) => {
    const baseDate = new Date(date);
    baseDate.setDate(baseDate.getDate() + amount);
    const newDate = baseDate.toISOString().split("T")[0];

    if (isPastDate(newDate)) return;

    clearMessages();
    setRecentlyReservedSlot(null);
    shouldScrollToResultsRef.current = false;
    setDate(newDate);
  };

  const handleSetToday = () => {
    clearMessages();
    setRecentlyReservedSlot(null);
    shouldScrollToResultsRef.current = false;
    setDate(getToday());
  };

  const handleManualDateChange = (newDate) => {
    if (!newDate) {
      setDate("");
      setAvailability([]);
      clearMessages();
      return;
    }

    if (isPastDate(newDate)) {
      setError("No pots seleccionar una data anterior a avui.");
      setSuccess("");
      setAvailability([]);
      setRecentlyReservedSlot(null);
      setDate(getToday());
      return;
    }

    clearMessages();
    setRecentlyReservedSlot(null);
    shouldScrollToResultsRef.current = false;
    setDate(newDate);
  };

  const handleReserve = async (slot) => {
    try {
      const token = localStorage.getItem("token");

      if (!token) {
        setError("Per reservar una pista, has d'iniciar sessió o crear un compte.");
        setSuccess("");
        setShowAuthHelp(true);
        return;
      }

      clearMessages();

      const slotKey = `${slot.court_id}-${slot.time_slot_id}`;
      setReservingSlot(slotKey);

      const response = await api.post("/reservations", {
        court_id: slot.court_id,
        time_slot_id: slot.time_slot_id,
        data_reserva: date,
        metode_pagament: paymentMethod,
      });

      const reservationData = response?.data?.data || null;

      setSuccess(
        response?.data?.message ||
          `Reserva confirmada a ${slot.nom_pista} (${slot.hora_inici} - ${slot.hora_fi}).`
      );

      setReservationSummary({
        codi_reserva: reservationData?.codi_reserva || "No disponible",
        preu_total:
          reservationData?.preu_total != null
            ? reservationData.preu_total
            : reservationData?.preu != null
            ? reservationData.preu
            : null,
        metode_pagament: reservationData?.metode_pagament || paymentMethod,
        estat_pagament: reservationData?.estat_pagament || "No disponible",
        nom_pista: slot.nom_pista,
        hora_inici: slot.hora_inici,
        hora_fi: slot.hora_fi,
        data_reserva: date,
      });

      setRecentlyReservedSlot({
        court_id: slot.court_id,
        time_slot_id: slot.time_slot_id,
        data_reserva: date,
      });

      setTimeout(() => {
        fetchAvailability(date);
        setReservingSlot(null);
      }, 180);
    } catch (err) {
      console.error(err);

      if (err.response?.status === 409 && err.response?.data?.error) {
        setError(err.response.data.error);
      } else if (err.response?.data?.error) {
        setError(err.response.data.error);
      } else {
        setError("Error creant la reserva.");
      }

      setSuccess("");
      setReservingSlot(null);
    }
  };

  useEffect(() => {
    fetchAvailability(date);
  }, [date]);

  useEffect(() => {
    if (success) return;
    if (!shouldScrollToResultsRef.current) return;

    if (!loading && availability.length > 0 && resultsRef.current) {
      scrollToElementWithOffset(resultsRef.current, 160);
      shouldScrollToResultsRef.current = false;
    }
  }, [availability, loading, success]);

  useEffect(() => {
    if (!success && !error && !showAuthHelp) return;

    const timeout = setTimeout(() => {
      scrollToElementWithOffset(topFeedbackRef.current, 120);
    }, 80);

    return () => clearTimeout(timeout);
  }, [success, error, showAuthHelp]);

  const filteredAvailability = useMemo(() => {
    if (!showOnlyAvailable) return availability;
    return availability.filter((slot) => slot.disponible);
  }, [availability, showOnlyAvailable]);

  const quickDays = useMemo(() => {
    const start = new Date(getToday());

    return Array.from({ length: 7 }, (_, index) => {
      const current = new Date(start);
      current.setDate(start.getDate() + index);

      return {
        iso: current.toISOString().split("T")[0],
        dayNumber: current.getDate(),
        weekday: formatShortWeekday(current),
        isToday: index === 0,
      };
    });
  }, []);

  const uniqueCourts = [
    ...new Set(filteredAvailability.map((slot) => slot.nom_pista)),
  ];

  const availableCount = filteredAvailability.filter(
    (slot) => slot.disponible
  ).length;

  const occupiedCount = filteredAvailability.length - availableCount;

  const previousDayDisabled = date <= getToday();

  return (
    <div className="avail-page__page">
      <div
        className={`avail-page__container ${isMobileView ? "avail-page__container--mobile" : ""}`}
      >
        <section
          className={`fade-in-up avail-page__hero ${isMobileView ? "avail-page__hero--mobile" : ""}`}
        >
          <div
            className={`avail-page__hero-grid ${isMobileView ? "avail-page__hero-grid--mobile" : ""}`}
          >
            <div>
              <span className="pb-chip">Reserva la teva pista</span>
              <h1
                className={`avail-page__title ${isMobileView ? "avail-page__title--mobile" : ""}`}
              >
                Consulta la disponibilitat d’una manera més clara i visual
              </h1>
              <p className="avail-page__subtitle">
                Selecciona un dia, revisa ràpidament quines pistes i franges
                tens disponibles i confirma la teva reserva amb una experiència
                més neta i agradable.
              </p>
            </div>

            <div className="avail-page__hero-date-card">
              <span className="avail-page__hero-date-label">Data seleccionada</span>
              <strong className="avail-page__hero-date-value">
                {formatDisplayDate(date)}
              </strong>

              <div className="avail-page__hero-date-meta">
                <span className="pb-badge-pill pb-badge-pill--blue">
                  {uniqueCourts.length || 0} pistes
                </span>
                <span className="pb-badge-pill pb-badge-pill--blue">
                  {filteredAvailability.length || 0} franges
                </span>
                <span className="pb-badge-pill pb-badge-pill--green">
                  {availableCount || 0} lliures
                </span>
              </div>
            </div>
          </div>
        </section>

        <section
          className={`fade-in-up delay-1 pb-surface-card avail-page__search-card ${isMobileView ? "avail-page__search-card--mobile" : ""}`}
        >
          <div
            className={`avail-page__search-header ${isMobileView ? "avail-page__search-header--mobile" : ""}`}
          >
            <div>
              <span className="pb-kicker">Selecció de dia</span>
              <h2 className="pb-panel-title">Tria el dia que vols jugar</h2>
              <p className="pb-panel-text">
                Pots usar els dies ràpids, canviar un dia enrere o endavant, o
                obrir el selector manual.
              </p>
            </div>

            <div className="avail-page__selection-hint">
              <span className="avail-page__selection-hint-label">Vista actual</span>
              <span className="avail-page__selection-hint-value">
                Disponibilitat del dia
              </span>
            </div>
          </div>

          <div
            className={`avail-page__quick-days-grid ${isMobileView ? "avail-page__quick-days-grid--mobile" : ""}`}
          >
            {quickDays.map((day) => (
              <button
                key={day.iso}
                onClick={() => {
                  clearMessages();
                  setRecentlyReservedSlot(null);
                  shouldScrollToResultsRef.current = false;
                  setDate(day.iso);
                }}
                className={`avail-page__quick-day-button ${date === day.iso ? "avail-page__quick-day-button--active" : ""}`}
              >
                <span className="avail-page__quick-day-weekday">{day.weekday}</span>
                <span className="avail-page__quick-day-number">{day.dayNumber}</span>
                <span className="avail-page__quick-day-label">
                  {day.isToday ? "Avui" : "Disponible"}
                </span>
              </button>
            ))}
          </div>

          <div
            className={`avail-page__controls ${isMobileView ? "avail-page__controls--mobile" : ""}`}
          >
            <button
              onClick={() => changeDay(-1)}
              className={`btn btn-secondary ${
                previousDayDisabled ? "is-disabled" : ""
              }`}
              disabled={previousDayDisabled}
            >
              ← Dia anterior
            </button>

            <div
              className={`avail-page__date-picker-wrapper ${isMobileView ? "avail-page__date-picker-wrapper--mobile" : ""}`}
            >
              <span className="avail-page__date-input-label">Triar data manualment</span>

              <button
                type="button"
                onClick={handleOpenDatePicker}
                className={`avail-page__custom-date-button ${isMobileView ? "avail-page__custom-date-button--mobile" : ""}`}
              >
                <span className="avail-page__custom-date-text">
                  {new Date(date).toLocaleDateString("ca-ES")}
                </span>
                <span className="avail-page__calendar-icon">📅</span>
              </button>

              <input
                ref={hiddenDateInputRef}
                type="date"
                value={date}
                min={getToday()}
                onChange={(e) => handleManualDateChange(e.target.value)}
                className="avail-page__hidden-date-input"
              />
            </div>

            <button
              onClick={() => changeDay(1)}
              className="btn btn-secondary"
            >
              Dia següent →
            </button>

            <button
              onClick={handleSetToday}
              className="btn btn-light"
            >
              Avui
            </button>

            <button
              onClick={() => {
                clearMessages();
                setRecentlyReservedSlot(null);
                shouldScrollToResultsRef.current = true;
                fetchAvailability(date);
              }}
              className="btn btn-primary"
            >
              {loading ? "Consultant..." : "Consultar disponibilitat"}
            </button>
          </div>

          <div className="avail-page__payment-box">
            <label htmlFor="paymentMethod" className="avail-page__payment-label">
              Mètode de pagament
            </label>

            <select
              id="paymentMethod"
              className="pb-input"
              value={paymentMethod}
              onChange={(e) => setPaymentMethod(e.target.value)}
            >
              <option value="online_simulat">Online</option>
              <option value="al_club">Club</option>
            </select>

            <p className="avail-page__payment-help">
              Selecciona com vols registrar el pagament de la reserva.
            </p>
          </div>

          <div className="avail-page__filters-row">
            <label className="avail-page__checkbox-label">
              <input
                type="checkbox"
                checked={showOnlyAvailable}
                onChange={(e) => setShowOnlyAvailable(e.target.checked)}
              />
              <span>Mostrar només franges disponibles</span>
            </label>
          </div>

          <div ref={topFeedbackRef} />

          {error && (
            <div className="scale-in avail-page__feedback-spacing">
              <div className="pb-feedback pb-feedback--error">
                <p className="avail-page__feedback-title-error">Hi ha hagut un problema</p>
                <p className="avail-page__feedback-text-error">{error}</p>
              </div>
            </div>
          )}

          {success && (
            <div className="scale-in avail-page__feedback-spacing">
              <div
                className={`pb-feedback pb-feedback--success ${isMobileView ? "avail-page__success-box--mobile" : "avail-page__success-box"}`}
              >
                <div>
                  <p className="avail-page__feedback-title-success">Reserva confirmada</p>
                  <p className="avail-page__feedback-text-success">{success}</p>
                </div>

                <div
                  className={`avail-page__success-actions ${isMobileView ? "avail-page__success-actions--mobile" : ""}`}
                >
                  <button
                    type="button"
                    onClick={() => navigate("/my-reservations")}
                    className="btn btn-success btn-sm"
                  >
                    Veure les meves reserves
                  </button>

                  <button
                    type="button"
                    onClick={() => setSuccess("")}
                    className="btn btn-outline-success btn-sm"
                  >
                    Continuar aquí
                  </button>
                </div>
              </div>
            </div>
          )}

          {success && reservationSummary && (
            <section
              className="scale-in pb-surface-card avail-page__success-card"
            >
              <div className="avail-page__success-header">
                <div>
                  <span className="avail-page__success-eyebrow">Reserva confirmada</span>
                  <h2 className="avail-page__success-title">
                    {reservationSummary.codi_reserva}
                  </h2>
                  <p className="avail-page__success-subtitle">
                    La reserva s’ha registrat correctament i ja tens el resum complet.
                  </p>
                </div>

                <Link to="/my-reservations" className="btn btn-sm">
                  Veure les meves reserves
                </Link>
              </div>

              <div className="avail-page__success-grid">
                <div className="avail-page__success-info-box">
                  <span className="avail-page__success-label">Pista</span>
                  <p className="avail-page__success-value">{reservationSummary.nom_pista}</p>
                </div>

                <div className="avail-page__success-info-box">
                  <span className="avail-page__success-label">Data</span>
                  <p className="avail-page__success-value">
                    {reservationSummary.data_reserva}
                  </p>
                </div>

                <div className="avail-page__success-info-box">
                  <span className="avail-page__success-label">Hora</span>
                  <p className="avail-page__success-value">
                    {reservationSummary.hora_inici} - {reservationSummary.hora_fi}
                  </p>
                </div>

                <div className="avail-page__success-info-box">
                  <span className="avail-page__success-label">Preu</span>
                  <p className="avail-page__success-value">
                    {reservationSummary.preu_total != null
                      ? `${Number(reservationSummary.preu_total).toFixed(2)} €`
                      : "No disponible"}
                  </p>
                </div>

                <div className="avail-page__success-info-box">
                  <span className="avail-page__success-label">Pagament</span>
                  <p className="avail-page__success-value">
                    {reservationSummary.metode_pagament}
                  </p>
                </div>

                <div className="avail-page__success-info-box">
                  <span className="avail-page__success-label">Estat pagament</span>
                  <p className="avail-page__success-value">
                    {reservationSummary.estat_pagament}
                  </p>
                </div>
              </div>
            </section>
          )}

          {showAuthHelp && (
            <div className="scale-in avail-page__feedback-spacing">
              <div
                className={`pb-feedback pb-feedback--info ${isMobileView ? "avail-page__auth-help-box--mobile" : "avail-page__auth-help-box"}`}
              >
                <div>
                  <p className="avail-page__auth-help-title">
                    Necessites iniciar sessió per reservar
                  </p>
                  <p className="avail-page__auth-help-text">
                    Si ja tens compte, entra ara. Si encara no, pots registrar-te
                    en molt poc temps.
                  </p>
                </div>

                <div
                  className={`avail-page__auth-help-actions ${isMobileView ? "avail-page__auth-help-actions--mobile" : ""}`}
                >
                  <Link
                    to="/login"
                    className="btn btn-primary btn-sm"
                  >
                    Iniciar sessió
                  </Link>

                  <Link
                    to="/register"
                    className="btn btn-light btn-sm"
                  >
                    Crear compte
                  </Link>
                </div>
              </div>
            </div>
          )}
        </section>

        {loading && (
          <LoadingSpinner
            text="Consultant la disponibilitat de pistes..."
            minHeight="220px"
          />
        )}

        {!loading && filteredAvailability.length > 0 && (
          <>
            <AvailabilitySummary availability={filteredAvailability} />

            <section
              ref={resultsRef}
              className="fade-in-up delay-2 avail-page__results-section"
            >
              <div
                className={`avail-page__results-header ${isMobileView ? "avail-page__results-header--mobile" : ""}`}
              >
                <div>
                  <span className="pb-kicker">Resultats</span>
                  <h2 className="pb-panel-title">Disponibilitat del dia</h2>
                  <p className="pb-panel-text">
                    Aquí tens la vista detallada de totes les franges segons els
                    filtres actuals.
                  </p>
                </div>

                <div className="avail-page__stats">
                  <span className="pb-badge-pill pb-badge-pill--blue">
                    {uniqueCourts.length} pistes
                  </span>
                  <span className="pb-badge-pill pb-badge-pill--blue">
                    {filteredAvailability.length} franges
                  </span>
                  <span className="pb-badge-pill pb-badge-pill--green">
                    {availableCount} lliures
                  </span>
                  <span className="pb-badge-pill pb-badge-pill--rose">
                    {occupiedCount} ocupades
                  </span>
                </div>
              </div>

              <AvailabilityTable
                availability={filteredAvailability}
                onReserve={handleReserve}
                reservingSlot={reservingSlot}
                recentlyReservedSlot={recentlyReservedSlot}
                selectedDate={date}
              />
            </section>
          </>
        )}

        {!loading && filteredAvailability.length === 0 && !error && (
          <section className="scale-in pb-surface-card avail-page__empty-state">
            <span className="avail-page__empty-icon">🎾</span>
            <h3 className="avail-page__empty-title">No hi ha disponibilitat per aquest dia</h3>
            <p className="avail-page__empty-text">
              Prova una altra data o desactiva el filtre de franges disponibles
              per veure totes les franges del sistema.
            </p>
          </section>
        )}
      </div>
    </div>
  );
}

export default AvailabilityPage;

import { useEffect, useMemo, useRef, useState } from "react";
import api from "../../api/axios";
import LoadingSpinner from "../../components/LoadingSpinner/LoadingSpinner";
import { scrollToElementWithOffset, normalizeSpaces } from "../../utils/helpers";
import "./ProfilePage.css";

function ProfilePage() {
  const topFeedbackRef = useRef(null);
  const profileFormRef = useRef(null);
  const passwordFormRef = useRef(null);
  const feedbackTimeoutRef = useRef(null);

  const [isTabletOrMobile, setIsTabletOrMobile] = useState(window.innerWidth <= 980);

  const [loadingProfile, setLoadingProfile] = useState(true);
  const [savingProfile, setSavingProfile] = useState(false);
  const [changingPassword, setChangingPassword] = useState(false);

  const [profile, setProfile] = useState(null);
  const [loadError, setLoadError] = useState("");

  const [formData, setFormData] = useState({
    nom: "",
    email: "",
  });

  const [passwordData, setPasswordData] = useState({
    currentPassword: "",
    newPassword: "",
  });

  const [showCurrentPassword, setShowCurrentPassword] = useState(false);
  const [showNewPassword, setShowNewPassword] = useState(false);
  const [capsLockCurrent, setCapsLockCurrent] = useState(false);
  const [capsLockNew, setCapsLockNew] = useState(false);

  const [feedback, setFeedback] = useState("");
  const [feedbackType, setFeedbackType] = useState("success");

  useEffect(() => {
    const handleResize = () => {
      setIsTabletOrMobile(window.innerWidth <= 980);
    };

    window.addEventListener("resize", handleResize);

    return () => window.removeEventListener("resize", handleResize);
  }, []);

  useEffect(() => {
    fetchProfile();

    return () => {
      if (feedbackTimeoutRef.current) {
        clearTimeout(feedbackTimeoutRef.current);
      }
    };
  }, []);



  const showFeedbackMessage = (message, type = "success") => {
    setFeedback(message);
    setFeedbackType(type);

    if (feedbackTimeoutRef.current) {
      clearTimeout(feedbackTimeoutRef.current);
    }

    feedbackTimeoutRef.current = setTimeout(() => {
      setFeedback("");
    }, 4500);

    setTimeout(() => {
      scrollToElementWithOffset(topFeedbackRef.current, 130);
    }, 80);
  };

  const clearFeedback = () => {
    setFeedback("");
  };

  const fetchProfile = async () => {
    try {
      setLoadingProfile(true);
      setLoadError("");
      clearFeedback();

      const response = await api.get("/auth/me");
      const userData = response?.data?.data || null;

      if (!userData) {
        throw new Error("No s'han pogut carregar les dades del compte.");
      }

      setProfile(userData);
      setFormData({
        nom: userData.nom || "",
        email: userData.email || "",
      });

      localStorage.setItem("user", JSON.stringify(userData));
    } catch (err) {
      console.error(err);

      const errorMessage =
        err.response?.data?.error ||
        "No s'han pogut carregar les dades del compte.";

      setLoadError(errorMessage);
      showFeedbackMessage(errorMessage, "error");
    } finally {
      setLoadingProfile(false);
    }
  };

  const roleLabel = useMemo(() => {
    if (!profile?.rol) return "Usuari";
    return profile.rol === "admin" ? "Administrador" : "Usuari";
  }, [profile]);

  const normalizedProfile = useMemo(() => {
    return {
      nom: normalizeSpaces(profile?.nom || ""),
      email: (profile?.email || "").trim().toLowerCase(),
    };
  }, [profile]);

  const normalizedForm = useMemo(() => {
    return {
      nom: normalizeSpaces(formData.nom || ""),
      email: (formData.email || "").trim().toLowerCase(),
    };
  }, [formData]);

  const hasProfileChanges = useMemo(() => {
    if (!profile) return false;

    return (
      normalizedProfile.nom !== normalizedForm.nom ||
      normalizedProfile.email !== normalizedForm.email
    );
  }, [profile, normalizedProfile, normalizedForm]);

  const firstName = useMemo(() => {
    if (!profile?.nom) return "Usuari";
    return profile.nom.split(" ")[0];
  }, [profile]);

  const initials = useMemo(() => {
    const fullName = profile?.nom?.trim() || "Usuari";
    const parts = fullName.split(" ").filter(Boolean);

    if (parts.length === 1) {
      return parts[0].slice(0, 1).toUpperCase();
    }

    return `${parts[0][0]}${parts[1][0]}`.toUpperCase();
  }, [profile]);

  const passwordChecks = useMemo(() => {
    const newPassword = passwordData.newPassword;

    return {
      minLength: newPassword.length >= 8,
      lowercase: /[a-z]/.test(newPassword),
      uppercase: /[A-Z]/.test(newPassword),
      number: /[0-9]/.test(newPassword),
      symbol: /[^A-Za-z0-9]/.test(newPassword),
      different:
        !!newPassword &&
        !!passwordData.currentPassword &&
        newPassword !== passwordData.currentPassword,
    };
  }, [passwordData]);

  const completedPasswordChecks = Object.values(passwordChecks).filter(Boolean).length;

  const passwordStrengthText =
    completedPasswordChecks <= 2
      ? "Baixa"
      : completedPasswordChecks <= 4
      ? "Mitjana"
      : "Alta";

  const passwordStrengthClass =
    completedPasswordChecks >= 5
      ? "pb-badge-pill pb-badge-pill--green"
      : completedPasswordChecks >= 3
      ? "pb-badge-pill pb-badge-pill--amber"
      : "pb-badge-pill pb-badge-pill--rose";

  const accountSummaryCards = [
    {
      label: "Estat del perfil",
      value: hasProfileChanges ? "Amb canvis" : "Actualitzat",
      text: hasProfileChanges
        ? "Hi ha informació pendent de guardar."
        : "Les dades actuals estan sincronitzades.",
    },
    {
      label: "Rol del compte",
      value: roleLabel,
      text:
        profile?.rol === "admin"
          ? "Tens accés a eines de gestió i administració."
          : "Tens accés a les funcionalitats habituals de reserva.",
    },
    {
      label: "Seguretat",
      value: `Nivell ${passwordStrengthText.toLowerCase()}`,
      text: "Pots reforçar la sessió actualitzant la contrasenya quan vulguis.",
    },
  ];

  const accountDetailItems = [
    {
      label: "Nom complet",
      value: profile?.nom || "-",
    },
    {
      label: "Correu",
      value: profile?.email || "-",
    },
    {
      label: "Rol",
      value: roleLabel,
    },
    {
      label: "Sessió",
      value: "Activa",
    },
  ];

  const handleProfileChange = (e) => {
    const { name, value } = e.target;

    setFormData((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  const handlePasswordInputChange = (e) => {
    const { name, value } = e.target;

    setPasswordData((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  const validateProfileForm = () => {
    const cleanNom = normalizeSpaces(formData.nom);
    const cleanEmail = formData.email.trim().toLowerCase();

    if (!cleanNom || !cleanEmail) {
      return "Has d'omplir el nom i el correu electrònic.";
    }

    if (cleanNom.length < 5) {
      return "El nom complet ha de tenir almenys 5 caràcters.";
    }

    const words = cleanNom.split(" ").filter(Boolean);
    if (words.length < 2) {
      return "Has d'introduir com a mínim nom i llinatge.";
    }

    const emailRegex = /^[^\s@]{2,}@[^\s@]{2,}\.[A-Za-z]{2,}$/;
    if (!emailRegex.test(cleanEmail)) {
      return "Introdueix un correu electrònic vàlid.";
    }

    return "";
  };

  const validatePasswordForm = () => {
    const { currentPassword, newPassword } = passwordData;

    if (!currentPassword.trim() || !newPassword.trim()) {
      return "Has d'omplir la contrasenya actual i la nova.";
    }

    if (newPassword.length < 8) {
      return "La nova contrasenya ha de tenir almenys 8 caràcters.";
    }

    if (!/[a-z]/.test(newPassword)) {
      return "La nova contrasenya ha d'incloure almenys una lletra minúscula.";
    }

    if (!/[A-Z]/.test(newPassword)) {
      return "La nova contrasenya ha d'incloure almenys una lletra majúscula.";
    }

    if (!/[0-9]/.test(newPassword)) {
      return "La nova contrasenya ha d'incloure almenys un número.";
    }

    if (!/[^A-Za-z0-9]/.test(newPassword)) {
      return "La nova contrasenya ha d'incloure almenys un símbol.";
    }

    if (currentPassword === newPassword) {
      return "La nova contrasenya ha de ser diferent de l'actual.";
    }

    return "";
  };

  const handleResetProfileChanges = () => {
    if (!profile) return;

    setFormData({
      nom: profile.nom || "",
      email: profile.email || "",
    });

    showFeedbackMessage("S'han restablert els canvis pendents del perfil.", "success");
  };

  const handleClearPasswordForm = () => {
    setPasswordData({
      currentPassword: "",
      newPassword: "",
    });

    setShowCurrentPassword(false);
    setShowNewPassword(false);
    setCapsLockCurrent(false);
    setCapsLockNew(false);

    showFeedbackMessage("S'han netejat els camps de la contrasenya.", "success");
  };

  const handleUpdateProfile = async (e) => {
    e.preventDefault();

    const validationError = validateProfileForm();
    if (validationError) {
      showFeedbackMessage(validationError, "error");
      return;
    }

    if (!hasProfileChanges) {
      showFeedbackMessage("No hi ha canvis per guardar al perfil.", "error");
      return;
    }

    try {
      setSavingProfile(true);
      clearFeedback();

      const payload = {
        nom: normalizeSpaces(formData.nom),
        email: formData.email.trim().toLowerCase(),
      };

      const response = await api.put("/auth/me", payload);
      const updatedUser = response?.data?.data || {
        ...profile,
        ...payload,
      };

      setProfile(updatedUser);
      setFormData({
        nom: updatedUser.nom || payload.nom,
        email: updatedUser.email || payload.email,
      });

      localStorage.setItem("user", JSON.stringify(updatedUser));
      window.dispatchEvent(new Event("profile-updated"));

      showFeedbackMessage("Perfil actualitzat correctament.", "success");
    } catch (err) {
      console.error(err);

      const backendError =
        err.response?.data?.error ||
        err.response?.data?.message ||
        "No s'ha pogut actualitzar el perfil.";

      showFeedbackMessage(backendError, "error");
    } finally {
      setSavingProfile(false);
    }
  };

  const handleChangePassword = async (e) => {
    e.preventDefault();

    const validationError = validatePasswordForm();
    if (validationError) {
      showFeedbackMessage(validationError, "error");
      return;
    }

    try {
      setChangingPassword(true);
      clearFeedback();

      await api.put("/auth/change-password", {
        currentPassword: passwordData.currentPassword,
        newPassword: passwordData.newPassword,
      });

      setPasswordData({
        currentPassword: "",
        newPassword: "",
      });

      setShowCurrentPassword(false);
      setShowNewPassword(false);
      setCapsLockCurrent(false);
      setCapsLockNew(false);

      showFeedbackMessage("Contrasenya canviada correctament.", "success");
    } catch (err) {
      console.error(err);

      const backendError =
        err.response?.data?.error ||
        err.response?.data?.message ||
        "No s'ha pogut canviar la contrasenya.";

      showFeedbackMessage(backendError, "error");
    } finally {
      setChangingPassword(false);
    }
  };

  const handleCapsLockCurrent = (e) => {
    setCapsLockCurrent(e.getModifierState("CapsLock"));
  };

  const handleCapsLockNew = (e) => {
    setCapsLockNew(e.getModifierState("CapsLock"));
  };

  if (loadingProfile) {
    return (
      <LoadingSpinner
        text="Carregant dades del teu compte..."
        minHeight="250px"
      />
    );
  }

  return (
    <div className="profile__page">
      <div
        className={`profile__container ${isTabletOrMobile ? "profile__container--mobile" : ""}`}
      >
        <section
          className={`fade-in-up profile__hero ${isTabletOrMobile ? "profile__hero--mobile" : ""}`}
        >
          <div
            className={`profile__hero-layout ${isTabletOrMobile ? "profile__hero-layout--mobile" : ""}`}
          >
            <div className="profile__hero-main">
              <span className="profile__hero-kicker">El meu compte</span>

              <div className="profile__hero-identity-row">
                <div className="profile__hero-avatar">{initials}</div>

                <div className="profile__hero-identity-text">
                  <h1
                    className={`profile__hero-title ${isTabletOrMobile ? "profile__hero-title--mobile" : ""}`}
                  >
                    Hola, {firstName}
                  </h1>

                  <p className="profile__hero-subtitle">
                    Revisa el perfil, mantén el correu actualitzat i reforça la
                    seguretat del compte des d’un espai molt més clar i ordenat.
                  </p>
                </div>
              </div>

              <div
                className={`profile__hero-actions ${isTabletOrMobile ? "profile__hero-actions--mobile" : ""}`}
              >
                <button
                  type="button"
                  className="btn btn-light"
                  onClick={() => scrollToElementWithOffset(profileFormRef.current, 110)}
                >
                  Editar perfil
                </button>

                <button
                  type="button"
                  className="btn btn-light"
                  onClick={() => scrollToElementWithOffset(passwordFormRef.current, 110)}
                >
                  Canviar contrasenya
                </button>
              </div>
            </div>

            <aside className="profile__hero-aside">
              <div className="profile__hero-aside-card">
                <div className="profile__hero-aside-top-row">
                  <div className="profile__hero-aside-identity">
                    <span className="profile__hero-aside-label">Compte actual</span>
                    <span className="profile__hero-aside-name">{profile?.nom || "Usuari"}</span>
                    <p className="profile__hero-aside-email">{profile?.email || "-"}</p>
                  </div>

                  <span
                    className={`pb-badge-pill ${
                      profile?.rol === "admin"
                        ? "pb-badge-pill--blue"
                        : "pb-badge-pill--green"
                    } profile__hero-role-badge`}
                  >
                    {roleLabel}
                  </span>
                </div>

                <div className="profile__hero-aside-mini-stats">
                  <div className="profile__hero-aside-mini-stat">
                    <span className="profile__hero-aside-mini-label">Perfil</span>
                    <span className="profile__hero-aside-mini-value">
                      {hasProfileChanges ? "Pendent" : "Correcte"}
                    </span>
                  </div>

                  <div className="profile__hero-aside-mini-stat">
                    <span className="profile__hero-aside-mini-label">Seguretat</span>
                    <span className="profile__hero-aside-mini-value">{passwordStrengthText}</span>
                  </div>
                </div>
              </div>
            </aside>
          </div>
        </section>

        <div ref={topFeedbackRef} />

        {feedback && (
          <section className="scale-in profile__feedback-section">
            <div
              className={`pb-feedback ${
                feedbackType === "success"
                  ? "pb-feedback--success"
                  : "pb-feedback--error"
              }`}
            >
              <p className="pb-feedback__text">{feedback}</p>
            </div>
          </section>
        )}

        {loadError ? (
          <section className="scale-in profile__feedback-section">
            <div className="pb-feedback pb-feedback--error profile__error-wrapper">
              <p className="profile__error-title">No s'han pogut carregar les dades</p>
              <p className="profile__error-text">{loadError}</p>

              <button
                type="button"
                className="btn btn-primary"
                onClick={fetchProfile}
              >
                Tornar-ho a intentar
              </button>
            </div>
          </section>
        ) : (
          <>
            <section
              className={`fade-in-up delay-1 profile__summary-grid ${isTabletOrMobile ? "profile__summary-grid--mobile" : ""}`}
            >
              {accountSummaryCards.map((item) => (
                <article key={item.label} className="pb-surface-card profile__summary-card">
                  <span className="profile__summary-label">{item.label}</span>
                  <span className="profile__summary-value">{item.value}</span>
                  <p className="profile__summary-text">{item.text}</p>
                </article>
              ))}
            </section>

            <div
              className={`profile__content-layout ${isTabletOrMobile ? "profile__content-layout--mobile" : ""}`}
            >
              <main className="profile__main-column">
                <section
                  ref={profileFormRef}
                  className="fade-in-up delay-2 pb-surface-card profile__card"
                >
                  <div className="profile__card-header">
                    <div>
                      <span className="pb-kicker">Dades personals</span>
                      <h2 className="pb-panel-title">Informació del compte</h2>
                      <p className="pb-panel-text">
                        Modifica el teu nom complet i el correu electrònic associat
                        a la sessió.
                      </p>
                    </div>

                    <span
                      className={`pb-badge-pill ${
                        hasProfileChanges
                          ? "pb-badge-pill--blue"
                          : "pb-badge-pill--green"
                      }`}
                    >
                      {hasProfileChanges ? "Canvis pendents" : "Sense canvis"}
                    </span>
                  </div>

                  <form onSubmit={handleUpdateProfile} className="profile__form">
                    <div
                      className={`profile__form-grid ${isTabletOrMobile ? "profile__form-grid--mobile" : ""}`}
                    >
                      <div className="pb-form-field">
                        <label htmlFor="nom" className="pb-form-label">
                          Nom i llinatges
                        </label>
                        <input
                          id="nom"
                          name="nom"
                          type="text"
                          value={formData.nom}
                          onChange={handleProfileChange}
                          placeholder="Ex: Pere Serra"
                          className="pb-input"
                          required
                        />
                      </div>

                      <div className="pb-form-field">
                        <label htmlFor="email" className="pb-form-label">
                          Correu electrònic
                        </label>
                        <input
                          id="email"
                          name="email"
                          type="email"
                          value={formData.email}
                          onChange={handleProfileChange}
                          placeholder="exemple@correu.com"
                          className="pb-input"
                          required
                        />
                      </div>
                    </div>

                    <div className="profile__info-strip">
                      <div className="profile__info-strip-icon">i</div>
                      <div>
                        <p className="profile__info-strip-title">Consell de perfil</p>
                        <p className="profile__info-strip-text">
                          Mantén un nom complet real i un correu vàlid per
                          identificar millor el compte i rebre comunicacions sense
                          errors.
                        </p>
                      </div>
                    </div>

                    <div
                      className={`profile__actions ${isTabletOrMobile ? "profile__actions--mobile" : ""}`}
                    >
                      <button
                        type="submit"
                        className="btn btn-primary"
                        disabled={savingProfile || !hasProfileChanges}
                      >
                        {savingProfile ? "Guardant canvis..." : "Guardar canvis"}
                      </button>

                      <button
                        type="button"
                        className="btn btn-light"
                        onClick={handleResetProfileChanges}
                        disabled={!hasProfileChanges || savingProfile}
                      >
                        Restablir
                      </button>
                    </div>
                  </form>
                </section>

                <section
                  ref={passwordFormRef}
                  className="fade-in-up delay-3 pb-surface-card profile__card"
                >
                  <div className="profile__card-header">
                    <div>
                      <span className="pb-kicker">Seguretat</span>
                      <h2 className="pb-panel-title">Canviar contrasenya</h2>
                      <p className="pb-panel-text">
                        Actualitza la contrasenya amb una validació clara i en temps
                        real.
                      </p>
                    </div>

                    <span className={passwordStrengthClass}>
                      Seguretat: {passwordStrengthText}
                    </span>
                  </div>

                  <form onSubmit={handleChangePassword} className="profile__form">
                    <div className="pb-form-field">
                      <label htmlFor="currentPassword" className="pb-form-label">
                        Contrasenya actual
                      </label>

                      <div
                        className={`profile__password-wrapper ${isTabletOrMobile ? "profile__password-wrapper--mobile" : ""}`}
                      >
                        <input
                          id="currentPassword"
                          name="currentPassword"
                          type={showCurrentPassword ? "text" : "password"}
                          value={passwordData.currentPassword}
                          onChange={handlePasswordInputChange}
                          onKeyDown={handleCapsLockCurrent}
                          onKeyUp={handleCapsLockCurrent}
                          placeholder="Introdueix la contrasenya actual"
                          className="pb-input"
                          required
                        />

                        <button
                          type="button"
                          className={`profile__show-button ${isTabletOrMobile ? "profile__show-button--mobile" : ""}`}
                          onClick={() => setShowCurrentPassword((prev) => !prev)}
                        >
                          {showCurrentPassword ? "Ocultar" : "Mostrar"}
                        </button>
                      </div>

                      {capsLockCurrent && (
                        <span className="profile__caps-warning">
                          ⚠️ Tens el bloqueig de majúscules activat
                        </span>
                      )}
                    </div>

                    <div className="pb-form-field">
                      <label htmlFor="newPassword" className="pb-form-label">
                        Nova contrasenya
                      </label>

                      <div
                        className={`profile__password-wrapper ${isTabletOrMobile ? "profile__password-wrapper--mobile" : ""}`}
                      >
                        <input
                          id="newPassword"
                          name="newPassword"
                          type={showNewPassword ? "text" : "password"}
                          value={passwordData.newPassword}
                          onChange={handlePasswordInputChange}
                          onKeyDown={handleCapsLockNew}
                          onKeyUp={handleCapsLockNew}
                          placeholder="Mínim 8 caràcters"
                          className="pb-input"
                          required
                        />

                        <button
                          type="button"
                          className={`profile__show-button ${isTabletOrMobile ? "profile__show-button--mobile" : ""}`}
                          onClick={() => setShowNewPassword((prev) => !prev)}
                        >
                          {showNewPassword ? "Ocultar" : "Mostrar"}
                        </button>
                      </div>

                      {capsLockNew && (
                        <span className="profile__caps-warning">
                          ⚠️ Tens el bloqueig de majúscules activat
                        </span>
                      )}
                    </div>

                    <div className="profile__checklist-panel">
                      <div className="profile__checklist-header">
                        <span className="profile__checklist-title">
                          Requisits de la nova contrasenya
                        </span>
                        <span className="profile__checklist-counter">
                          {completedPasswordChecks}/6 complets
                        </span>
                      </div>

                      <div className="profile__progress-track">
                        <div
                          className="profile__progress-fill"
                          style={{
                            width: `${(completedPasswordChecks / 6) * 100}%`,
                          }}
                        />
                      </div>

                      <div className="profile__checklist">
                        <div className="profile__check-item">
                          <span className={passwordChecks.minLength ? "profile__check-ok" : "profile__check-pending"}>
                            {passwordChecks.minLength ? "✓" : "•"}
                          </span>
                          <span>Almenys 8 caràcters</span>
                        </div>

                        <div className="profile__check-item">
                          <span className={passwordChecks.lowercase ? "profile__check-ok" : "profile__check-pending"}>
                            {passwordChecks.lowercase ? "✓" : "•"}
                          </span>
                          <span>Inclou una minúscula</span>
                        </div>

                        <div className="profile__check-item">
                          <span className={passwordChecks.uppercase ? "profile__check-ok" : "profile__check-pending"}>
                            {passwordChecks.uppercase ? "✓" : "•"}
                          </span>
                          <span>Inclou una majúscula</span>
                        </div>

                        <div className="profile__check-item">
                          <span className={passwordChecks.number ? "profile__check-ok" : "profile__check-pending"}>
                            {passwordChecks.number ? "✓" : "•"}
                          </span>
                          <span>Inclou un número</span>
                        </div>

                        <div className="profile__check-item">
                          <span className={passwordChecks.symbol ? "profile__check-ok" : "profile__check-pending"}>
                            {passwordChecks.symbol ? "✓" : "•"}
                          </span>
                          <span>Inclou un símbol</span>
                        </div>

                        <div className="profile__check-item">
                          <span className={passwordChecks.different ? "profile__check-ok" : "profile__check-pending"}>
                            {passwordChecks.different ? "✓" : "•"}
                          </span>
                          <span>Ha de ser diferent de l’actual</span>
                        </div>
                      </div>
                    </div>

                    <div
                      className={`profile__actions ${isTabletOrMobile ? "profile__actions--mobile" : ""}`}
                    >
                      <button
                        type="submit"
                        className="btn btn-primary"
                        disabled={changingPassword}
                      >
                        {changingPassword
                          ? "Canviant contrasenya..."
                          : "Canviar contrasenya"}
                      </button>

                      <button
                        type="button"
                        className="btn btn-light"
                        onClick={handleClearPasswordForm}
                        disabled={
                          changingPassword ||
                          (!passwordData.currentPassword && !passwordData.newPassword)
                        }
                      >
                        Netejar camps
                      </button>
                    </div>
                  </form>
                </section>
              </main>

              <aside className="profile__sidebar-column">
                <div
                  className={`profile__sidebar-stack ${isTabletOrMobile ? "profile__sidebar-stack--mobile" : ""}`}
                >
                  <section
                    className="fade-in-up delay-3 pb-surface-card profile__sidebar-card"
                  >
                    <div className="profile__sidebar-card-header">
                      <span className="pb-kicker">Resum del compte</span>
                      <h3 className="profile__sidebar-title">Vista ràpida</h3>
                    </div>

                    <div className="profile__account-list">
                      {accountDetailItems.map((item) => (
                        <div key={item.label} className="profile__account-list-item">
                          <span className="profile__account-list-label">{item.label}</span>
                          <span className="profile__account-list-value">{item.value}</span>
                        </div>
                      ))}
                    </div>
                  </section>

                  <section
                    className="fade-in-up delay-4 pb-surface-card profile__sidebar-card"
                  >
                    <div className="profile__sidebar-card-header">
                      <span className="pb-kicker">Estat actual</span>
                      <h3 className="profile__sidebar-title">Seguiment</h3>
                    </div>

                    <div className="profile__status-stack">
                      <div className="profile__status-row">
                        <span className="profile__status-label">Canvis al perfil</span>
                        <span
                          className={`pb-badge-pill ${
                            hasProfileChanges
                              ? "pb-badge-pill--blue"
                              : "pb-badge-pill--green"
                          }`}
                        >
                          {hasProfileChanges ? "Pendents" : "Al dia"}
                        </span>
                      </div>

                      <div className="profile__status-row">
                        <span className="profile__status-label">Contrasenya</span>
                        <span className={passwordStrengthClass}>{passwordStrengthText}</span>
                      </div>

                      <div className="profile__status-row">
                        <span className="profile__status-label">Sessió</span>
                        <span className="pb-badge-pill pb-badge-pill--green">Activa</span>
                      </div>
                    </div>
                  </section>

                  <section
                    className="fade-in-up delay-4 pb-surface-card profile__sidebar-card"
                  >
                    <div className="profile__sidebar-card-header">
                      <span className="pb-kicker">Bones pràctiques</span>
                      <h3 className="profile__sidebar-title">Recomanacions</h3>
                    </div>

                    <div className="profile__tip-list">
                      <div className="profile__tip-item">
                        <span className="profile__tip-bullet">•</span>
                        <p className="profile__tip-text">
                          Revisa el correu si canvies l’adreça principal del compte.
                        </p>
                      </div>

                      <div className="profile__tip-item">
                        <span className="profile__tip-bullet">•</span>
                        <p className="profile__tip-text">
                          Evita reutilitzar la mateixa contrasenya en altres serveis.
                        </p>
                      </div>

                      <div className="profile__tip-item">
                        <span className="profile__tip-bullet">•</span>
                        <p className="profile__tip-text">
                          Guarda els canvis del perfil abans de sortir de la pàgina.
                        </p>
                      </div>
                    </div>
                  </section>
                </div>
              </aside>
            </div>
          </>
        )}
      </div>
    </div>
  );
}

export default ProfilePage;
